import{_ as s,o as n,c as e,ag as d}from"./chunks/framework.D54qew5K.js";const m=JSON.parse('{"title":"指令文件详解","description":"SOUL.md、USER.md、AGENTS.md、MEMORY.md 四层指令系统","frontmatter":{"title":"指令文件详解","description":"SOUL.md、USER.md、AGENTS.md、MEMORY.md 四层指令系统"},"headers":[],"relativePath":"guide/instruction-files.md","filePath":"guide/instruction-files.md","lastUpdated":1774526771000}'),t={name:"guide/instruction-files.md"};function l(p,a,i,o,c,r){return n(),e("div",null,[...a[0]||(a[0]=[d(`<h1 id="指令文件详解" tabindex="-1">指令文件详解 <a class="header-anchor" href="#指令文件详解" aria-label="Permalink to &quot;指令文件详解&quot;">​</a></h1><p>AeroLoongClaw 为每个群组维护四层长期指令文件，分别对应不同的职责层级。四层文件在磁盘上独立存放，运行时由 OpenCode Runner 按优先级合并后加载。</p><h2 id="四层文件角色" tabindex="-1">四层文件角色 <a class="header-anchor" href="#四层文件角色" aria-label="Permalink to &quot;四层文件角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>用途</th><th>内容示例</th><th>建议行数</th></tr></thead><tbody><tr><td><code>SOUL.md</code></td><td>核心人格与行事风格</td><td>价值观、语气、说话方式</td><td>≤ 50 行</td></tr><tr><td><code>USER.md</code></td><td>用户偏好与协作方式</td><td>称呼、语言、输出格式偏好</td><td>≤ 50 行</td></tr><tr><td><code>AGENTS.md</code></td><td>运行规则与工具纪律</td><td>工具调用规范、安全边界、记忆写入协议</td><td>≤ 150 行</td></tr><tr><td><code>MEMORY.md</code></td><td>长期积累的事实与决策</td><td>项目背景、已确认结论、反复出现的需求</td><td>≤ 100 行</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">四层文件的分工原则</p><ul><li><code>SOUL.md</code>：很少变动，定义&quot;我是谁&quot;</li><li><code>USER.md</code>：偶尔更新，记录&quot;用户喜欢什么&quot;</li><li><code>AGENTS.md</code>：很少变动，规定&quot;我怎么做&quot;</li><li><code>MEMORY.md</code>：主动维护，记录&quot;我知道什么&quot;</li></ul></div><h2 id="文件位置" tabindex="-1">文件位置 <a class="header-anchor" href="#文件位置" aria-label="Permalink to &quot;文件位置&quot;">​</a></h2><h3 id="群组本地文件" tabindex="-1">群组本地文件 <a class="header-anchor" href="#群组本地文件" aria-label="Permalink to &quot;群组本地文件&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>groups/{group}/</span></span>
<span class="line"><span>├── SOUL.md      # 群组人格覆盖</span></span>
<span class="line"><span>├── USER.md      # 群组用户偏好覆盖</span></span>
<span class="line"><span>├── AGENTS.md    # 群组运行规则覆盖</span></span>
<span class="line"><span>└── MEMORY.md    # 群组长期记忆（增量追加）</span></span></code></pre></div><h3 id="全局默认文件" tabindex="-1">全局默认文件 <a class="header-anchor" href="#全局默认文件" aria-label="Permalink to &quot;全局默认文件&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/workspace/global/          # 容器内全局工作区</span></span>
<span class="line"><span>├── SOUL.md      # 不使用（SOUL 不可全局）</span></span>
<span class="line"><span>├── USER.md      # 不使用（USER 不可全局）</span></span>
<span class="line"><span>├── AGENTS.md    # 全局共享规则，所有群组继承</span></span>
<span class="line"><span>└── MEMORY.md    # 全局长期记忆，所有群组共享</span></span></code></pre></div><p>::: note 全局目录在容器内为 <code>/workspace/global/</code>；Host 端对应目录由容器挂载决定。 :::</p><h2 id="合并策略" tabindex="-1">合并策略 <a class="header-anchor" href="#合并策略" aria-label="Permalink to &quot;合并策略&quot;">​</a></h2><p>四层文件采用两种不同的合并策略：</p><h3 id="覆盖策略-override-—-soul-user-agents" tabindex="-1">覆盖策略（Override）— SOUL / USER / AGENTS <a class="header-anchor" href="#覆盖策略-override-—-soul-user-agents" aria-label="Permalink to &quot;覆盖策略（Override）— SOUL / USER / AGENTS&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>群组文件存在 → 加载群组文件</span></span>
<span class="line"><span>群组文件不存在 → 加载全局文件（作为后备）</span></span></code></pre></div><p>对于 SOUL.md、USER.md、AGENTS.md，同一时间只加载一份文件（群组优先，全局兜底）。</p><h3 id="增量追加策略-additive-—-memory" tabindex="-1">增量追加策略（Additive）— MEMORY <a class="header-anchor" href="#增量追加策略-additive-—-memory" aria-label="Permalink to &quot;增量追加策略（Additive）— MEMORY&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 先加载全局 MEMORY.md</span></span>
<span class="line"><span>2. 再加载群组 MEMORY.md</span></span></code></pre></div><p>全局记忆和群组记忆都会被保留，按顺序拼接。适合记录跨群组成立的通用事实和仅在当前群组有效的特定上下文。</p><h3 id="合并流程图" tabindex="-1">合并流程图 <a class="header-anchor" href="#合并流程图" aria-label="Permalink to &quot;合并流程图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>开始加载指令</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ├─► SOUL.md   ──群组存在?──是──► 加载群组版本</span></span>
<span class="line"><span>     │                    │</span></span>
<span class="line"><span>     │                    否</span></span>
<span class="line"><span>     │                    ▼</span></span>
<span class="line"><span>     │              加载全局版本（若有）</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ├─► USER.md   ──群组存在?──是──► 加载群组版本</span></span>
<span class="line"><span>     │                    │</span></span>
<span class="line"><span>     │                    否</span></span>
<span class="line"><span>     │                    ▼</span></span>
<span class="line"><span>     │              加载全局版本（若有）</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     ├─► AGENTS.md ──群组存在?──是──► 加载群组版本</span></span>
<span class="line"><span>     │                    │</span></span>
<span class="line"><span>     │                    否</span></span>
<span class="line"><span>     │                    ▼</span></span>
<span class="line"><span>     │              加载全局版本（若有）</span></span>
<span class="line"><span>     │</span></span>
<span class="line"><span>     └─► MEMORY.md ──► 加载全局版本 ──► 加载群组版本（两者都加载）</span></span></code></pre></div><h2 id="优先级链" tabindex="-1">优先级链 <a class="header-anchor" href="#优先级链" aria-label="Permalink to &quot;优先级链&quot;">​</a></h2><p>四层文件的加载顺序（对应优先级从高到低）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>SOUL.md  →  USER.md  →  AGENTS.md  →  MEMORY.md</span></span>
<span class="line"><span>（人格）    （偏好）     （规则）       （记忆）</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">优先级仅影响加载顺序，不影响覆盖语义</p><p>对于 SOUL/USER/AGENTS，同一层级不会同时存在两份（群组覆盖全局）。对于 MEMORY，全局和群组都会保留（增量追加）。</p></div><h2 id="实际加载顺序" tabindex="-1">实际加载顺序 <a class="header-anchor" href="#实际加载顺序" aria-label="Permalink to &quot;实际加载顺序&quot;">​</a></h2><p>当 OpenCode 加载指令时，文件按以下顺序读入（最终决定运行时可见内容）：</p><ol><li><code>SOUL.md</code>（群组或全局后备）</li><li><code>USER.md</code>（群组或全局后备）</li><li><code>AGENTS.md</code>（群组或全局后备）</li><li><code>MEMORY.md</code>（全局 + 群组拼接）</li><li><code>.opencode/instructions.md</code>（运行时生成的汇总指令）</li><li><code>.opencode/interaction-workflow.md</code>（交互工作流规范）</li><li><code>.opencode/skills-index.md</code>（技能索引，若有）</li></ol><h2 id="opencode-运行时资产" tabindex="-1"><code>.opencode/</code> 运行时资产 <a class="header-anchor" href="#opencode-运行时资产" aria-label="Permalink to &quot;\`.opencode/\` 运行时资产&quot;">​</a></h2><p>四层指令文件在容器启动时会被写入 <code>.opencode/</code> 目录，作为 OpenCode 的指令来源：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/workspace/group/.opencode/</span></span>
<span class="line"><span>├── instructions.md       # 四层指令汇总（由运行时写入）</span></span>
<span class="line"><span>├── interaction-workflow.md  # 交互工作流规范</span></span>
<span class="line"><span>├── skills-index.md       # 技能索引（由 skills-loader 生成）</span></span>
<span class="line"><span>├── agents/               # Agent 模板（从 agent-templates/ 复制）</span></span>
<span class="line"><span>│   ├── build.md</span></span>
<span class="line"><span>│   ├── planner.md</span></span>
<span class="line"><span>│   ├── researcher.md</span></span>
<span class="line"><span>│   ├── executor.md</span></span>
<span class="line"><span>│   └── reviewer.md</span></span>
<span class="line"><span>├── commands/             # Command 模板（从 command-templates/ 复制）</span></span>
<span class="line"><span>│   ├── complex-plan.md</span></span>
<span class="line"><span>│   ├── complex-research.md</span></span>
<span class="line"><span>│   ├── complex-execute.md</span></span>
<span class="line"><span>│   └── complex-review.md</span></span>
<span class="line"><span>├── skills/               # 技能符号链接 → /workspace/skills/&lt;name&gt;</span></span>
<span class="line"><span>├── plugins/              # 插件预留目录</span></span>
<span class="line"><span>└── reload.json           # 资产生成元数据</span></span></code></pre></div><h3 id="资产生成时机" tabindex="-1">资产生成时机 <a class="header-anchor" href="#资产生成时机" aria-label="Permalink to &quot;资产生成时机&quot;">​</a></h3><p><code>.opencode/</code> 资产在容器启动时由 <code>writeNativeOpenCodeAssets()</code> 生成（<code>opencode-native-assets.ts:330</code>），条件为 <code>nativeAssetsEnabled !== false</code>（默认启用）。</p><h3 id="instructions-md-生成逻辑" tabindex="-1">instructions.md 生成逻辑 <a class="header-anchor" href="#instructions-md-生成逻辑" aria-label="Permalink to &quot;instructions.md 生成逻辑&quot;">​</a></h3><p><code>instructions.md</code> 的内容并非简单拼接四层文件，而是：</p><ol><li>读取 <code>SOUL.md</code>（群组或全局）</li><li>读取 <code>USER.md</code>（群组或全局）</li><li>读取 <code>AGENTS.md</code>（群组或全局）</li><li>读取 <code>MEMORY.md</code>（全局 + 群组，按序拼接）</li><li>拼接为单个字符串，写入 <code>.opencode/instructions.md</code></li></ol><p>该文件路径通过 <code>opencode.json</code> 的 <code>instructions</code> 字段注册到 OpenCode（<code>opencode-config.ts:120</code>）。</p><h2 id="主群组与普通群组的差异" tabindex="-1">主群组与普通群组的差异 <a class="header-anchor" href="#主群组与普通群组的差异" aria-label="Permalink to &quot;主群组与普通群组的差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>主群组（Main）</th><th>普通群组</th></tr></thead><tbody><tr><td><code>SOUL.md</code></td><td>独立人格</td><td>独立人格</td></tr><tr><td><code>USER.md</code></td><td>主协作者信息</td><td>群组用户偏好</td></tr><tr><td><code>AGENTS.md</code></td><td>包含主控线程额外权限章节</td><td>常规运行规则</td></tr><tr><td><code>MEMORY.md</code></td><td>全局长期记忆</td><td>群组长期记忆</td></tr></tbody></table><p>主群组的 <code>AGENTS.md</code> 包含额外的「主控制线程权限」章节，授予注册群组、管理技能、配置挂载等能力。</p><h2 id="更新时机建议" tabindex="-1">更新时机建议 <a class="header-anchor" href="#更新时机建议" aria-label="Permalink to &quot;更新时机建议&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>何时更新</th><th>更新频率</th></tr></thead><tbody><tr><td><code>SOUL.md</code></td><td>人格或风格发生根本性变化</td><td>很低</td></tr><tr><td><code>USER.md</code></td><td>发现用户新的稳定偏好</td><td>低</td></tr><tr><td><code>AGENTS.md</code></td><td>运行规则需要调整</td><td>很低</td></tr><tr><td><code>MEMORY.md</code></td><td>有价值跨会话事实、确认的决策</td><td>中</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">写入 MEMORY.md 的判断标准</p><ul><li>跨会话都有价值的事实</li><li>用户明确要求&quot;记住这个&quot;</li><li>任务结束时产生了未来会用到的新认知</li></ul></div><div class="danger custom-block"><p class="custom-block-title">不应写入 MEMORY.md 的内容</p><ul><li>当前任务的临时过程、中间草稿</li><li>已能从文件推导出的信息</li><li>不确定是否长期有效的猜测</li><li>用户偏好（应写入 USER.md）</li></ul></div><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./concepts.html">核心概念</a> — 四层指令系统的概述</li><li><a href="/aeroloongclaw-docs/reference/architecture.html">架构详解</a> — 容器内运行时完整流程</li><li><a href="/aeroloongclaw-docs/reference/mcp-tools.html">MCP 工具参考</a> — 定时任务调度工具 <code>schedule_task</code> 等完整列表</li></ul>`,46)])])}const u=s(t,[["render",l]]);export{m as __pageData,u as default};
